{
  "title": "कम-शॉट उदाहरण",
  "group": "प्रॉम्प्ट संरचना",
  "options": [
    {
      "text": "अधिक उदाहरण हमेशा बेहतर परिणाम देते हैं"
    },
    {
      "text": "प्रॉम्प्ट में 3–5 उच्च गुणवत्ता वाले, विविध उदाहरण"
    },
    {
      "text": "कम-शॉट उदाहरण केवल वर्गीकरण कार्यों में मदद करते हैं"
    },
    {
      "text": "उदाहरण उपयोगकर्ता प्रश्न के बाद आएं, न कि पहले"
    }
  ],
  "questionProse": [
    "अधिकांश उत्पादन उपयोग के मामलों में, अनुकूल कम-शॉट उदाहरण रणनीति है:"
  ],
  "explanationProse": [
    "कम-शॉट उदाहरण आउटपुट संगतता और फॉर्मेट अनुपालन में निपुणता से सुधार करते हैं। अधिकांश कार्यों के लिए अनुकूल बिंदु **3–5 उच्च गुणवत्ता वाले, विविध उदाहरण** हैं।\n\n    क्यों अधिक नहीं? प्रत्येक उदाहरण की टोकन लागत होती है। 5–10 उदाहरणों के बाद, सीमांत लाभ घटता रहता है जबकि टोकन लागत बढ़ती रहती है। अधिक उदाहरणों से मॉडल उदाहरणों के अनुरूप ओवर-फिट होने की संभावना बढ़ जाती है।\n\n    विविधता की आवश्यकता: अगर आपके सभी उदाहरण एक ही प्रकार के इनपुट हैं, तो मॉडल अंतिम मामलों के लिए व्यापक नहीं होगा। अपने सबसे महत्वपूर्ण विविधताओं को कवर करने वाले उदाहरण शामिल करें।\n\n    स्थान: उदाहरण उपयोगकर्ता प्रश्न से पहले आएं, सिस्टम प्रॉम्प्ट के भाग के रूप में या पूर्व-परिभाषित बातचीत के टर्न में — न कि बाद में।"
  ]
}
